var Math               = require('Math');

var eventId  = getEventData('event_id') || ('ET-' + getTimestampMillis());
var currency = getEventData('currency') || 'SAR';
var value    = getEventData('value')    || 0;
var orderId  = getEventData('transaction_id') || '';
var cIds     = getEventData('content_ids') || '';

function clean(o){var r={};for(var k in o){if(o[k]!==""&&o[k]!=null)r[k]=o[k];}return r;}

var ud = clean({
  em:                getEventData('user_data.em')  || getEventData('up.em'),
  ph:                getEventData('user_data.ph')  || getEventData('up.ph'),
  fn:                getEventData('user_data.fn')  || getEventData('up.fn'),
  ln:                getEventData('user_data.ln')  || getEventData('up.ln'),
  external_id:       getEventData('user_data.external_id') || getEventData('up.external_id'),
  fbp:               getEventData('up.fbp'),
  fbc:               getEventData('up.fbc'),
  client_ip_address: data.clientIp,
  client_user_agent: data.userAgent
});

var cd = clean({
  currency:     currency,
  value:        value,
  order_id:     orderId,
  content_ids:  cIds ? [cIds] : undefined,
  content_type: 'product'
});

var payload = JSON.stringify({ data: [{
  event_name:    data.eventName,
  event_time:    Math.floor(getTimestampMillis()/1000),
  event_id:      eventId,
  action_source: 'website',
  user_data:     ud,
  custom_data:   cd
}]});

var url = 'https://graph.facebook.com/v18.0/' + encodeUriComponent(data.pixelId) +
            '/events?access_token=' + encodeUriComponent(data.accessToken);

sendHttpRequest(url, {
  method:'POST',
  headers:{'Content-Type':'application/json'},
  timeout:8000
}, payload).then(function(r){
  if(r.statusCode>=200&&r.statusCode<300){ data.gtmOnSuccess(); }
  else{ data.gtmOnFailure(); }
}, data.gtmOnFailure);

