var sendHttpRequest    = require('sendHttpRequest');
var JSON               = require('JSON');
var getEventData       = require('getEventData');
var getTimestampMillis = require('getTimestampMillis');
var Math               = require('Math');

var ts=Math.floor(getTimestampMillis()/1000);function p2(n){return n<10?"0"+n:""+n;}
var rem=ts%86400;var hh=Math.floor(rem/3600);rem=rem%3600;var mm=Math.floor(rem/60);var ss=rem%60;
var totalDays=Math.floor(ts/86400);var y=1970;while(true){var diy=(y%4===0&&(y%100!==0||y%400===0))?366:365;if(totalDays<diy)break;totalDays=totalDays-diy;y=y+1;}
var leap=(y%4===0&&(y%100!==0||y%400===0));var mD=[31,leap?29:28,31,30,31,30,31,31,30,31,30,31];var mo=0;while(totalDays>=mD[mo]){totalDays=totalDays-mD[mo];mo=mo+1;}
var convTime=y+"-"+p2(mo+1)+"-"+p2(totalDays+1)+" "+p2(hh)+":"+p2(mm)+":"+p2(ss)+" +0000";

var ids = [];
var em  = getEventData('user_data.em') || getEventData('up.em');
var ph  = getEventData('user_data.ph') || getEventData('up.ph');
if(em) ids.push({hashedEmail: em});
if(ph) ids.push({hashedPhoneNumber: ph});

var payload = JSON.stringify({
  conversions: [{
    conversionAction:   'customers/' + data.conversionId + '/conversionActions/' + data.conversionLabel,
    conversionDateTime: convTime,
    conversionValue:    getEventData('value')    || 0,
    currencyCode:       getEventData('currency') || 'SAR',
    orderId:            getEventData('transaction_id'),
    gclid:              getEventData('ep.gclid')  || getEventData('up.gclid'),
    wbraid:             getEventData('ep.wbraid'),
    gbraid:             getEventData('ep.gbraid'),
    userIdentifiers:    ids
  }],
  partialFailure: true
});

// NOTE: Google Ads API needs an OAuth2 Bearer token + developer-token.
// Configure these in the sGTM tag UI after import, or replace via
// additional TEXT parameters on this template.
sendHttpRequest('https://googleads.googleapis.com/v14/customers/' + data.conversionId + ':uploadConversions', {
  method:'POST',
  headers:{'Content-Type':'application/json'},
  timeout:8000
}, payload).then(function(r){
  if(r.statusCode>=200&&r.statusCode<300){ data.gtmOnSuccess(); }
  else{ data.gtmOnFailure(); }
}, data.gtmOnFailure);

